NUNCA mezclado con 'notification.received'.

S→C

socket.on('notification.received', (notification) => {
  // notification.kind => routing a la UI
  // Kinds disponibles:
  // 'message_received' → abrir conversación
  // 'call_missed' → historial de llamadas
  // 'meeting_started' → unirse al meeting
  // 'meeting_cancelled' → actualizar calendar
  // 'meeting_rescheduled' → actualizar calendar
  // 'support_ticket_new' → (agentes) abrir ticket
  // 'support_ticket_claimed' → (customer) ver ticket
  // 'support_ticket_escalated' → ver ticket
  // 'support_ticket_resolved' → ver ticket
  // 'support_ticket_reopened' → (agentes) ver ticket
  // 'signature_signer_invited' → ir al portal firma
  // 'signature_completed' → descargar documento firmado
  // 'signature_expired' → renovar proceso de firma
  // 'recording_ready' → descargar grabación
})
